## context.WithValue

`go
func WithValue(parent Context, key, val any) Context {
 if parent == nil {
 panic("cannot create context from nil parent")
 }
 if key == nil {
 panic("nil key")
 }
 if !reflectlite.TypeOf(key).Comparable() {
 panic("key is not comparable")
 }
 return &valueCtx{parent, key, val}
}

type valueCtx struct {
 Context
 key, val any
}
`

context.WithValueлҠ” л¶ҖлӘЁ м»Ён…ҚмҠӨнҠёлҘј л©ӨлІ„ ліҖмҲҳлЎң к°–лҠ” м»Ён…ҚмҠӨнҠёлҘј мғқм„ұн•©лӢҲлӢӨ.

`go
func (c *valueCtx) Value(key any) any {
 // мһҗмӢ (n м„ёлҢҖ)мқҙ keyм—җ л§һлҠ” Contextмқё кІҪмҡ° мһҗмӢ мқҳ к°’мқ„ л°ҳнҷҳ
 if c.key == key {
 return c.val
 }

 // м•„лӢҢ кІҪмҡ° л¶ҖлӘЁ(n-1 м„ёлҢҖ) ContextлҘј нҷ•мқё
 return value(c.Context, key)
}

func value(c Context, key any) any {
 for {
 switch ctx := c.(type) {
 case *valueCtx:
 // л¶ҖлӘЁ(n-1 м„ёлҢҖ)к°Җ keyм—җ л§һлҠ” Contextмқё кІҪмҡ° л¶ҖлӘЁмқҳ к°’мқ„ л°ҳнҷҳ
 if key == ctx.key {
 return ctx.val
 }

 // м•„лӢҢ кІҪмҡ° л¶ҖлӘЁмқҳ л¶ҖлӘЁ(n-2 м„ёлҢҖ) ContextлҘј нғҗмғүн•ҳкё° мң„н•ҙ мӨҖл№„
 c = ctx.Context
 case *cancelCtx:
 // лӮҙл¶Җ мҪ”л“ңлҘј мң„н•ң мІҳлҰ¬
 if key == &cancelCtxKey {
 return c
 }
 c = ctx.Context
 case *timerCtx:
 // лӮҙл¶Җ мҪ”л“ңлҘј мң„н•ң мІҳлҰ¬
 if key == &cancelCtxKey {
 return ctx.cancelCtx
 }
 c = ctx.Context
 case *emptyCtx:
