`go

 "context"
 "fmt"
 "sync"

 corev1 "k8s.io/api/core/v1"
 "k8s.io/apimachinery/pkg/labels"
 ctrl "sigs.k8s.io/controller-runtime"
 "sigs.k8s.io/controller-runtime/pkg/client"
 "sigs.k8s.io/controller-runtime/pkg/reconcile"
)

// NamespaceFilterлҠ” label selectorм—җ л§Өм№ӯлҗҳлҠ” namespace м§‘н•©мқ„ кҙҖлҰ¬н•©лӢҲлӢӨ.
// мІ« лІҲм§ё Refresh м „м—җлҠ” system namespaceлҘј м ңмҷён•ң лӘЁл“  namespaceлҘј м°ЁлӢЁн•©лӢҲлӢӨ.
type NamespaceFilter struct {
 client client.Client
 selector labels.Selector
 systemNamespace string

 mu sync.RWMutex
 ready bool
 namespaces map[string]struct{}
}

func NewNamespaceFilter(c client.Client, selector labels.Selector, systemNS string) *NamespaceFilter {
 return &NamespaceFilter{
 client: c,
 selector: selector,
 systemNamespace: systemNS,
 namespaces: make(map[string]struct{}),
 }
}

// RefreshлҠ” л§Өм№ӯлҗҳлҠ” namespace м „мІҙлҘј лӢӨмӢң мЎ°нҡҢн•ҳм—¬ мәҗмӢңлҘј к°ұмӢ н•©лӢҲлӢӨ.
func (f *NamespaceFilter) Refresh(ctx context.Context) error {
 var nsList corev1.NamespaceList
 if err := f.client.List(ctx, &nsList, client.MatchingLabelsSelector{Selector: f.selector}); err != nil {
 return fmt.Errorf("listing namespaces for filter refresh: %w", err)
 }

 newSet := make(map[string]struct{}, len(nsList.Items))
 for _, ns := range nsList.Items {
 newSet[ns.Name] = struct{}{}
 }

 f.mu.Lock()
 f.namespaces = newSet
 f.ready = true
 f.mu.Unlock()

 return nil
}

// MatchesлҠ” system namespaceмқҙкұ°лӮҳ мәҗмӢңм—җ мһҲлҠ” namespaceмқём§Җ нҷ•мқён•©лӢҲлӢӨ.
// мІ« лІҲм§ё Refresh м „м—җлҠ” system namespaceлҘј м ңмҷён•ҳкі  falseлҘј л°ҳнҷҳн•©лӢҲлӢӨ.
func (f *NamespaceFilter) Matches(namespace string) bool {
 if namespace == f.systemNamespace {
 return true
 }

 f.mu.RLock()
 defer f.mu.RUnlock()

 if !f.ready {
 return false
 }

 _, ok := f.namespaces[namespace]
 return ok
}

// NamespaceWatchReconcilerлҠ” Namespace мқҙлІӨнҠёлҘј к°җмӢңн•ҳкі  NamespaceFilterлҘј к°ұмӢ н•©лӢҲлӢӨ.
type NamespaceWatchReconciler struct {
 Filter *NamespaceFilter
}

func (r *NamespaceWatchReconciler) Reconcile(ctx context.Context, _ reconcile.Request) (reconcile.Result, error) {
 return ctrl.Result{}, r.Filter.Refresh(ctx)
}

func (r *NamespaceWatchReconciler) SetupWithManager(mgr ctrl.Manager) error {
 return ctrl.NewControllerManagedBy(mgr).
 For(&corev1.Namespace{}).
 Named("namespace-watcher").
 Complete(r)
}
`

