м»ӨмҠӨн…ҖмңјлЎң л§Ңл“  нғҖмһ… мӨ‘м—җ ліҖнҷҳмқ„ нҶөн•ҙ validatorк°Җ мІҳлҰ¬н•  мҲҳ мһҲлҠ” нғҖмһ…мқ„ л§Ңл“Ө мҲҳ мһҲлҠ” кІҪмҡ° RegisterCustomTypeFuncлҘј мӮ¬мҡ©н•ҳм—¬ нғҖмһ… ліҖнҷҳ н•ЁмҲҳлҘј л“ұлЎқн•  мҲҳ мһҲмҠөлӢҲлӢӨ.

`go
package main

 "fmt"
 "reflect"

 "github.com/go-playground/validator/v10"
)

type PhoneNumber struct {
 CountryCode string
 Number string
}

func PhoneNumberToString(field reflect.Value) interface{} {
 if v, ok := field.Interface().(PhoneNumber); ok {
 if v == (PhoneNumber{}) {
 return ""
 }
 return fmt.Sprintf("+%s%s", v.CountryCode, v.Number)
 }
 return ""
}

type User struct {
 PhoneNumber PhoneNumber validate:"omitempty,e164"
}

var validate *validator.Validate

func main() {
 validate = validator.New()
 validate.RegisterCustomTypeFunc(PhoneNumberToString, PhoneNumber{})

 cases := []User{
 {},
 {
 PhoneNumber: PhoneNumber{
 CountryCode: "82",
 Number: "1012345678",
 },
 },
 {
 PhoneNumber: PhoneNumber{
 CountryCode: "x",
 Number: "x",
 },
 },
 }

 for _, c := range cases {
 if err := validate.Struct(c); err != nil {
 fmt.Println(err)
 } else {
 fmt.Println("OK")
 }
 }
}
`

