 .def("transmit",
 [](lot::Uart &self, py::bytes data) {
 std::string str = data;
 if(str.size() > 0) {
 self.transmit(reinterpret_cast(
 const_cast(str.c_str())),
 str.size());
 }
 })
 .def("receive", [](lot::Uart &self) {
 uint16_t size = self.available();
 if(size > 0) {
 uint8_t *buf = new uint8_t[size];
 self.receive(buf, size);
 py::bytes data(reinterpret_cast(buf), size);
 delete[] buf;
 return data;
 }
 return py::bytes("");
 });
