 // argsлҘј мӮ¬мҡ©н•ҳм—¬ action.payloadлҘј м„Өм •н•©лӢҲлӢӨ.
 return { payload: {} };
 },
 reducer: (state: S, action: PayloadAction): S | void => {
 // action.payloadлҘј л°ӣм•„м„ң stateлҘј ліҖкІҪн•©лӢҲлӢӨ.
